    asal: "wahdat al-wujud — وحدة الوجود (kesatuan wujud)",
    kategori: "puncak",
    alias: ["wahdatul wujud", "kesatuan wujud", "wahdat", "ibn arabi", "wahdatus syuhud", "sirhindi", "panteisme", "wujud tunggal"],
